export function getGlobalExpansionStats() {
  return {
    totalMatches: GLOBAL_EXPANSION_MATCHES.length,
    hotMatches: GLOBAL_EXPANSION_MATCHES.filter(m => m.signalStatus === 'hot').length,
    highNpsMatches: GLOBAL_EXPANSION_MATCHES.filter(m => m.rowNps >= 9).length,
    enterpriseMatches: GLOBAL_EXPANSION_MATCHES.filter(m => m.usEmployees >= 1000).length,
    totalUsContacts: GLOBAL_EXPANSION_MATCHES.reduce((acc, m) => acc + m.usContacts, 0)
  };
}
